Here's a production-quality binary search with comprehensive error handling, both iterative and recursive variants, and thorough tests.

## Iterative Approach (Recommended)

```javascript
/**
 * Binary search on a sorted array.
 * @param {number[]} arr - Sorted array (ascending)
 * @param {number} target - Value to search for
 * @returns {number} Index of target, or -1 if not found
 * @throws {TypeError} If arr is not an array or target is not a number
 * @throws {Error} If array is not sorted
 */
function binarySearch(arr, target) {
  // Input validation
  if (!Array.isArray(arr)) {
    throw new TypeError(`Expected array, got ${typeof arr}`);
  }
  if (typeof target !== 'number' || Number.isNaN(target)) {
    throw new TypeError(`Expected number for target, got ${typeof target}`);
  }
  if (arr.length === 0) return -1;

  // Validate sorted order (check a sample for performance)
  if (arr.length > 1 && arr[0] > arr[arr.length - 1]) {
    throw new Error('Array must be sorted in ascending order');
  }

  let left = 0;
  let right = arr.length - 1;

  while (left <= right) {
    // Avoid potential integer overflow (not an issue in JS, but good practice)
    const mid = left + Math.floor((right - left) / 2);

    if (arr[mid] === target) return mid;
    if (arr[mid] < target) {
      left = mid + 1;
    } else {
      right = mid - 1;
    }
  }

  return -1;
}
```

## Recursive Approach

```javascript
function binarySearchRecursive(arr, target, left = 0, right = arr.length - 1) {
  if (!Array.isArray(arr)) {
    throw new TypeError(`Expected array, got ${typeof arr}`);
  }
  if (left > right) return -1;

  const mid = left + Math.floor((right - left) / 2);

  if (arr[mid] === target) return mid;
  if (arr[mid] < target) {
    return binarySearchRecursive(arr, target, mid + 1, right);
  }
  return binarySearchRecursive(arr, target, left, mid - 1);
}
```

## Tests

